<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="人员名称"
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-select
                  :allowClear="true"
                  showSearch
                  optionFilterProp="lable"
                  v-model:value="queryParams.userId"
                  placeholder="请选择人员名称"
                >
                  <a-select-option
                    v-for="item in selUserList"
                    :key="item.userId"
                    :lable="item.name"
                    :value="item.userId"
                  >
                    {{ item.name }}
                  </a-select-option>
                </a-select>
              </a-form-item>
            </a-col>
            <a-col :md="8" :sm="24">
              <a-form-item label="所属科室">
                <a-select
                  :allowClear="true"
                  showSearch
                  optionFilterProp="lable"
                  v-model:value="queryParams.teamId"
                  placeholder="请选择所属科室"
                >
                  <a-select-option
                    v-for="item in selteamList"
                    :key="item.id"
                    :lable="item.name"
                    :value="item.id"
                  >
                    {{ item.name }}
                  </a-select-option>
                </a-select>
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a-button style="margin-left: 8px" @click="reset">重置</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
        <template #certificateUrl="{ text }"
          ><img :src="text" alt="" style="whild: 50px; height: 50px"
        /></template>
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item
            label="人员名称"
            :rules="[{ required: true, message: '该项必填！' }]"
          >
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.userId"
              placeholder="请选人员名称"
            >
              <a-select-option
                v-for="item in selUserList"
                :key="item.userId"
                :lable="item.name"
                :value="item.userId"
              >
                {{ item.name }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="所属科室" :rules="[{ required: true, message: '该项必填！' }]">
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.teamId"
              placeholder="请选择所属科室"
            >
              <a-select-option
                v-for="item in selteamList"
                :key="item.id"
                :lable="item.name"
                :value="item.id"
              >
                {{ item.name }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="技术职称">
            <a-input
              placeholder="请输入技术职称"
              v-model:value="form.postName"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="职称等级">
            <a-input
              placeholder="请输入职称等级"
              v-model:value="form.postGrade"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="证书名称">
            <a-input
              placeholder="请输入证书名称"
              v-model:value="form.certificateName"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="专业技能">
            <a-input placeholder="请输入专业技能" v-model:value="form.skill" />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="证书图片">
            <a-upload
              v-model:file="file"
              :show-upload-list="false"
              :customRequest="customRequest"
              :before-upload="beforeUpload"
            >
              <img
                v-if="form.certificateUrl"
                :src="form.certificateUrl"
                alt="avatar"
                style="width: 100px; heidht: 100px"
              />
              <div v-else>
                <a-button>
                  <UploadOutlined></UploadOutlined>
                  点击上传实验室照片
                </a-button>
              </div>
            </a-upload>
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "人员名称",
    dataIndex: "userName",
  },
  {
    title: "所属科室",
    dataIndex: "teamName",
  },
  {
    title: "技术职称",
    dataIndex: "postName",
  },
  {
    title: "职称等级",
    dataIndex: "postGrade",
  },
  {
    title: "证书名称",
    dataIndex: "certificateName",
  },
  {
    title: "证书图片",
    dataIndex: "certificateUrl",
    slots: { customRender: "certificateUrl" },
  },
  {
    title: "专业技能",
    dataIndex: "skill",
  },
];
const rules = {

};
import {
  TechnicistList,
  addTechnicist,
  getTechnicist,
  delTechnicist,
  editTechnicist,
  UserList,
  teamListAll,
} from "@/server/http/api/team";
import { message } from "ant-design-vue";
import { uploadFile ,delFile} from "@/server/http/api/File";
import { UploadOutlined } from "@ant-design/icons-vue";
export default {
  name: "QueryList",
  components: { UploadOutlined },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      rules:rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {
        userId: "",
      },
      file: null,
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        userId: undefined,
        teamId: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      //用户列表
      selUserList: [],
      //科室列表
      selteamList: [],
      //用来存储修改的临时文件路径
      updateUrl: null,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },
  mounted() {
    this.getteamList();
    this.getUserList();
  },
  methods: {
    delFileMethod(e) {
      delFile({fileUrl:e}).then((res) => {});
    },
    //证书图片上传
    customRequest(info) {
      const formData = new FormData();
      formData.append("file", info.file);
      uploadFile(formData).then((res) => {
        this.form.certificateUrl = res.data.data.fileUrl;
      });
    },
    //证书图片传前
    beforeUpload(file) {
      const isJpgOrPng =
        file.type === "image/jpeg" || file.type === "image/png";
      if (!isJpgOrPng) {
        message.error("只能上传图片!");
      }
      const isLt5M = file.size / 1024 / 1024 < 5;

      if (!isLt5M) {
        message.error("图片大小不能超过5M!");
      }
      return isJpgOrPng && isLt5M;
    },
    //获取用户
    getUserList() {
      UserList().then((res) => {
        var data = res.data.data;
        this.selUserList = data;
      });
    },
    //获取科室
    getteamList() {
      teamListAll().then((res) => {
        var data = res.data;
        this.selteamList = data.data;
      });
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      TechnicistList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    handleOk(e) {
      if (
        !this.form.userId ||
        !this.form.teamId
      ) {
        message.warning("缺少必填参数!");
         return;
      }
      this.submitForm();
    },

    reset() {
      (this.queryParams = {
        current: 1,
        size: 10,
        userId: undefined,
        teamId: undefined,
      }),
        this.getList();
    },
    handleCancel(e) {
      if (this.form.certificateUrl != null&&this.updateUrl != this.form.certificateUrl) {
        this.delFileMethod(this.form.certificateUrl);
      }
      this.updateUrl=null;
      this.form = {};
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      //this.reset();
      this.open = true;
      this.title = "添加人员信息";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getTechnicist(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改人员信息";
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        if(this.form.certificateUrl!=this.updateUrl){
          this.delFileMethod(this.updateUrl);
        }
        editTechnicist(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addTechnicist(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delTechnicist(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>